        },
        "result_properties": ["optb88vdw_bandgap", "bulk_modulus_kv"],
    },
)
data = response.json()
for m in data["results"][:10]:
    print(f"{m['jid']:12s} {m['formula']:10s} "
          f"gap={m.get('optb88vdw_bandgap', 'N/A')} eV  "
          f"Kv={m.get('bulk_modulus_kv', 'N/A')} GPa")
